import { eventsFindAllOptionsSchema, eventsFindOptionsSchema, } from './schemas/event.js';
import { contactsFindOptionsSchema, contactsFindAllOptionsSchema, } from './schemas/contact.js';
import { ticketsFindAllOptionsSchema, ticketsFindOptionsSchema, } from './schemas/ticket.js';
import { paymentsFindAllOptionsSchema, paymentsFindOptionsSchema, } from './schemas/payment.js';
import { webhooksFindAllOptionsSchema, webhooksFindOptionsSchema, } from './schemas/webhook.js';
import { workspacesFindAllOptionsSchema, workspacesFindOptionsSchema, } from './schemas/workspace.js';
import { categoriesFindAllOptionsSchema, categoriesFindOptionsSchema, } from './schemas/category.js';
import { ticketBatchesFindAllOptionsSchema, ticketBatchesFindOptionsSchema, } from './schemas/ticket-batch.js';
import { baseOptionsSchema } from './schemas/resource-options.js';
import models from './models/index.js';
export const eventsResource = {
    findAll: (options = {}, adapter) => {
        const validatedOptions = eventsFindAllOptionsSchema.parse(options);
        return adapter.get({ path: models.event.path, type: models.event.endpoint, ...validatedOptions });
    },
    find: (id, options = {}, adapter) => {
        const validatedOptions = eventsFindOptionsSchema.parse(options);
        return adapter.get({ path: `${models.event.path}/${id}`, type: models.event.endpoint, ...validatedOptions });
    },
};
export const ticketsResource = {
    findAll: (options, adapter) => {
        const validatedOptions = ticketsFindAllOptionsSchema.parse(options);
        return adapter.get({ path: models.ticket.path, type: models.ticket.endpoint, ...validatedOptions });
    },
    find: (id, options = {}, adapter) => {
        const validatedOptions = ticketsFindOptionsSchema.parse(options);
        return adapter.get({
            path: `${models.ticket.path}/${id}`,
            type: models.ticket.endpoint,
            ...validatedOptions,
        });
    },
    create: (json, options = {}, adapter) => {
        const validatedOptions = baseOptionsSchema.parse(options);
        if (!models.ticket.operations.create)
            throw new Error('Ticket create operation not found');
        const validatedData = models.ticket.operations.create.schema.parse(json);
        return adapter.post({
            // eslint-disable-next-line @typescript-eslint/no-explicit-any, @typescript-eslint/consistent-type-assertions
            json: validatedData,
            path: models.ticket.path,
            type: models.ticket.endpoint,
            ...validatedOptions,
        });
    },
};
